{
  "expo": {
    "name": "fasola",
    "slug": "fasola",
    "version": "1.0.0",
    "orientation": "portrait",
    "icon": "./assets/images/icon.png",
    "scheme": "fasola",
    "userInterfaceStyle": "automatic",
    "newArchEnabled": true,
    "ios": {
      "supportsTablet": true,
      "bundleIdentifier": "com.eryknapierala.fasola",
      "appleTeamId": "SRBZTFXF42",
      "infoPlist": {
        "UIFileSharingEnabled": true,
        "LSSupportsOpeningDocumentsInPlace": true,
        "ITSAppUsesNonExemptEncryption": false
      }
    },
    "web": {
      "output": "static",
      "favicon": "./assets/icon/bold.svg"
    },
    "plugins": [
      "expo-router",
      [
        "expo-splash-screen",
        {
          "image": "./assets/images/splash-icon.png",
          "imageWidth": 200,
          "resizeMode": "contain",
          "backgroundColor": "#7B9E30",
          "dark": {
            "backgroundColor": "#7B9E30"
          }
        }
      ],
      [
        "expo-build-properties",
        {
          "ios": {
            "deploymentTarget": "17.0"
          }
        }
      ],
      "./plugins/withAutoSigning",
      "expo-font",
      "expo-localization",
      "expo-web-browser",
      "./modules/icloud-sync/app.plugin.js"
    ],
    "experiments": {
      "typedRoutes": true,
      "reactCompiler": true
    },
    "extra": {
      "router": {},
      "eas": {
        "projectId": "06ade8bf-bcef-44f3-91a9-b21c88c5ebe0"
      }
    },
    "owner": "eryknapierala",
    "android": {
      "package": "com.eryknapierala.fasola"
    }
  }
}
